import{_ as e,c as t,o as s,ag as i}from"./chunks/framework.ko2zIC2c.js";const u=JSON.parse('{"title":"Your First PostgreSQL Function as an API","description":"","frontmatter":{"layout":"doc"},"headers":[],"relativePath":"blog/my-first-function.md","filePath":"blog/my-first-function.md"}'),n={name:"blog/my-first-function.md"};function r(l,a,o,p,h,c){return s(),t("div",null,a[0]||(a[0]=[i(`<h1 id="your-first-postgresql-function-as-an-api" tabindex="-1">Your First PostgreSQL Function as an API <a class="header-anchor" href="#your-first-postgresql-function-as-an-api" aria-label="Permalink to &quot;Your First PostgreSQL Function as an API&quot;">​</a></h1><p class="blog-meta"><span class="tag">Concept</span> · <span class="tag">Getting Started</span></p><hr><p>The traditional approach to building REST APIs involves writing endpoint handlers, data validation, serialization logic, and database queries—often in separate layers that must be kept in sync. NpgsqlRest takes a different approach: <strong>your database functions become your API</strong>.</p><h2 id="the-problem" tabindex="-1">The Problem <a class="header-anchor" href="#the-problem" aria-label="Permalink to &quot;The Problem&quot;">​</a></h2><p>Consider what typically happens when you need to expose a simple operation as an API:</p><ol><li>Write a database query or stored procedure</li><li>Create a data access layer</li><li>Write a service layer with business logic</li><li>Define DTOs for request/response</li><li>Create an API controller</li><li>Add validation</li><li>Generate or write API documentation</li><li>Write (or generate) a client SDK</li></ol><p>That&#39;s a lot of moving parts for what might be a single database function.</p><h2 id="the-npgsqlrest-approach" tabindex="-1">The NpgsqlRest Approach <a class="header-anchor" href="#the-npgsqlrest-approach" aria-label="Permalink to &quot;The NpgsqlRest Approach&quot;">​</a></h2><p>With NpgsqlRest, you define your function in PostgreSQL:</p><div class="language-sql vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">create</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> function</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> hello_world</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">()</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">returns</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> text</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">language</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> sql</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">as</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> $$</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">select</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;Hello, World!&#39;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$$;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>And it&#39;s immediately available as an API endpoint:</p><div class="language-http vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">http</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">POST</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> /api/hello-world</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>That&#39;s it. No controllers, no serialization code, no manual endpoint registration.</p><h2 id="what-you-get-automatically" tabindex="-1">What You Get Automatically <a class="header-anchor" href="#what-you-get-automatically" aria-label="Permalink to &quot;What You Get Automatically&quot;">​</a></h2><p>When NpgsqlRest discovers your function, it generates:</p><ul><li><strong>HTTP endpoint</strong> with proper method and path</li><li><strong>Type-safe parameters</strong> from function arguments</li><li><strong>JSON serialization</strong> for complex return types</li><li><strong>OpenAPI documentation</strong> describing the endpoint</li><li><strong>TypeScript client</strong> with full type inference</li></ul><h2 id="why-this-matters" tabindex="-1">Why This Matters <a class="header-anchor" href="#why-this-matters" aria-label="Permalink to &quot;Why This Matters&quot;">​</a></h2><p>This isn&#39;t just about writing less code—it&#39;s about <strong>single source of truth</strong>. Your PostgreSQL function signature <em>is</em> your API contract. Change the function, and everything updates: the endpoint, the documentation, and the generated client.</p><p>When you modify a function&#39;s return type and rebuild your TypeScript client, type errors appear instantly if your frontend code is now incompatible. You catch breaking changes at compile time, not in production.</p><h2 id="try-it-yourself" tabindex="-1">Try It Yourself <a class="header-anchor" href="#try-it-yourself" aria-label="Permalink to &quot;Try It Yourself&quot;">​</a></h2><p>The full working example is available in the examples repository:</p><p>→ <a href="https://github.com/NpgsqlRest/npgsqlrest-docs/tree/main/examples/1_my_first_function" target="_blank" rel="noreferrer">View the complete example on GitHub</a></p><hr><p class="blog-nav"><p><strong>Next:</strong> <a href="/blog/static-type-checking.html">Static Type Safety with Generated Clients</a> <em>(coming soon)</em></p></p>`,25)]))}const g=e(n,[["render",r]]);export{u as __pageData,g as default};
